		defer ReturnPanicError(ch)
		params := GetArg(optionalArgs, 0, map[string]any{})
		_ = params

		response := (<-this.PrivateGetAccountConfig(params))
		PanicOnError(response)
		//
		//     {
		//         "code": "0",
		//         "data": [
		//             {
		//                 "acctLv": "2",
		//                 "acctStpMode": "cancel_maker",
