func (this *OkxCore) ParseTicker(ticker any, optionalArgs ...any) any {
	//
	//      {
	//          "instType":"SWAP",
	//          "instId":"BTC-USDT-SWAP",
	//          "markPx":"200",
	//          "ts":"1597026383085"
	//      }
	//
	//     {
	//         "instType": "SPOT",
	//         "instId": "ETH-BTC",
	//         "last": "0.07319",
	//         "lastSz": "0.044378",
	//         "askPx": "0.07322",
	//         "askSz": "4.2",
	//         "bidPx": "0.0732",
	//         "bidSz": "6.050058",
	//         "open24h": "0.07801",
	//         "high24h": "0.07975",
	//         "low24h": "0.06019",
	//         "volCcy24h": "11788.887619",
	//         "vol24h": "167493.829229",
	//         "ts": "1621440583784",
	//         "sodUtc0": "0.07872",
	//         "sodUtc8": "0.07345"
	//     }
	//     {
	//          instId: 'LTC-USDT',
	//          idxPx: '65.74',
	//          open24h: '65.37',
	//          high24h: '66.15',
	//          low24h: '64.97',
	//          sodUtc0: '65.68',
	//          sodUtc8: '65.54',
	//          ts: '1728467346900'
	//     },
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var timestamp any = this.SafeInteger(ticker, "ts")
	var marketId any = this.SafeString(ticker, "instId")
	market = this.SafeMarket(marketId, market, "-")
	var symbol any = GetValue(market, "symbol")
	var last any = this.SafeString(ticker, "last")
	var open any = this.SafeString(ticker, "open24h")
	var spot any = this.SafeBool(market, "spot", false)
	var quoteVolume any = Ternary(IsTrue(spot), this.SafeString(ticker, "volCcy24h"), nil)
	var baseVolume any = this.SafeString(ticker, "vol24h")
	var high any = this.SafeString(ticker, "high24h")
	var low any = this.SafeString(ticker, "low24h")
	return this.SafeTicker(map[string]any{
		"symbol":        symbol,
		"timestamp":     timestamp,
		"datetime":      this.Iso8601(timestamp),
		"high":          high,
		"low":           low,
		"bid":           this.SafeString(ticker, "bidPx"),
		"bidVolume":     this.SafeString(ticker, "bidSz"),
		"ask":           this.SafeString(ticker, "askPx"),
		"askVolume":     this.SafeString(ticker, "askSz"),
		"vwap":          nil,
		"open":          open,
		"close":         last,
		"last":          last,
		"previousClose": nil,
		"change":        nil,
		"percentage":    nil,
		"average":       nil,
		"baseVolume":    baseVolume,
		"quoteVolume":   quoteVolume,
		"markPrice":     this.SafeString(ticker, "markPx"),
		"indexPrice":    this.SafeString(ticker, "idxPx"),
		"info":          ticker,
	}, market)
}

