func (this *OkxCore) ParseTrade(trade any, optionalArgs ...any) any {
	//
	// public fetchTrades
	//
	//     {
	//         "instId": "ETH-BTC",
	//         "side": "sell",
	//         "sz": "0.119501",
	//         "px": "0.07065",
	//         "tradeId": "15826757",
	//         "ts": "1621446178316"
	//     }
	//
	// option: fetchTrades
	//
	//     {
	//         "fillVol": "0.46387625976562497",
	//         "fwdPx": "26299.754935451125",
	//         "indexPx": "26309.7",
	//         "instFamily": "BTC-USD",
	//         "instId": "BTC-USD-230526-26000-C",
	//         "markPx": "0.042386283557554236",
	//         "optType": "C",
	//         "px": "0.0415",
	//         "side": "sell",
	//         "sz": "90",
	//         "tradeId": "112",
	//         "ts": "1683907480154"
	//     }
	//
	// private fetchMyTrades
	//
	//     {
	//         "side": "buy",
	//         "fillSz": "0.007533",
	//         "fillPx": "2654.98",
	//         "fee": "-0.000007533",
	//         "ordId": "317321390244397056",
	//         "instType": "SPOT",
	//         "instId": "ETH-USDT",
	//         "clOrdId": "",
	//         "posSide": "net",
	//         "billId": "317321390265368576",
	//         "tag": "0",
	//         "execType": "T",
	//         "tradeId": "107601752",
	//         "feeCcy": "ETH",
	//         "ts": "1621927314985"
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var id any = this.SafeString(trade, "tradeId")
	var marketId any = this.SafeString(trade, "instId")
	market = this.SafeMarket(marketId, market, "-")
	var symbol any = GetValue(market, "symbol")
	var timestamp any = this.SafeInteger(trade, "ts")
	var price any = this.SafeString2(trade, "fillPx", "px")
	var amount any = this.SafeString2(trade, "fillSz", "sz")
	var side any = this.SafeString(trade, "side")
	var orderId any = this.SafeString(trade, "ordId")
	var feeCostString any = this.SafeString(trade, "fee")
	var fee any = nil
	if IsTrue(!IsEqual(feeCostString, nil)) {
		var feeCostSigned any = Precise.StringNeg(feeCostString)
		var feeCurrencyId any = this.SafeString(trade, "feeCcy")
		var feeCurrencyCode any = this.SafeCurrencyCode(feeCurrencyId)
		fee = map[string]any{
			"cost":     feeCostSigned,
			"currency": feeCurrencyCode,
		}
	}
	var takerOrMaker any = this.SafeString(trade, "execType")
	if IsTrue(IsEqual(takerOrMaker, "T")) {
		takerOrMaker = "taker"
	} else if IsTrue(IsEqual(takerOrMaker, "M")) {
		takerOrMaker = "maker"
	}
	return this.SafeTrade(map[string]any{
		"info":         trade,
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"symbol":       symbol,
		"id":           id,
		"order":        orderId,
		"type":         nil,
		"takerOrMaker": takerOrMaker,
		"side":         side,
		"price":        price,
		"amount":       amount,
		"cost":         nil,
		"fee":          fee,
	}, market)
}

