		response := (<-this.PrivateGetAssetDepositAddress(this.Extend(request, params)))
		PanicOnError(response)
		//
		//     {
		//         "code": "0",
		//         "msg": "",
		//         "data": [
		//             {
		//                 "addr": "okbtothemoon",
		//                 "memo": "971668", // may be missing
		//                 "tag":"52055", // may be missing
		//                 "pmtId": "", // may be missing
