func (this *OkxCore) ParseMarketLeverageTiers(info any, optionalArgs ...any) any {
	/**
	 * @ignore
	 * @method
	 * @param {object} info Exchange response for 1 market
	 * @param {object} market CCXT market
	 */
	//
	//    [
	//        {
	//            "baseMaxLoan": "500",
	//            "imr": "0.1",
	//            "instId": "ETH-USDT",
	//            "maxLever": "10",
	//            "maxSz": "500",
	//            "minSz": "0",
	//            "mmr": "0.03",
	//            "optMgnFactor": "0",
	//            "quoteMaxLoan": "200000",
	//            "tier": "1",
	//            "uly": ""
	//        },
	//        ...
	//    ]
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var tiers any = []any{}
	for i := 0; IsLessThan(i, GetArrayLength(info)); i++ {
		var tier any = GetValue(info, i)
		var marketId any = this.SafeString(tier, "instId")
		AppendToArray(&tiers, map[string]any{
			"tier":                  this.SafeInteger(tier, "tier"),
			"symbol":                this.SafeSymbol(marketId, market),
			"currency":              GetValue(market, "quote"),
			"minNotional":           this.SafeNumber(tier, "minSz"),
			"maxNotional":           this.SafeNumber(tier, "maxSz"),
			"maintenanceMarginRate": this.SafeNumber(tier, "mmr"),
			"maxLeverage":           this.SafeNumber(tier, "maxLever"),
			"info":                  tier,
		})
	}
	return tiers
}

