func (this *OkxCore) ParseConversion(conversion any, optionalArgs ...any) any {
	//
	// fetchConvertQuote
	//
	//     {
	//         "baseCcy": "ETH",
	//         "baseSz": "0.01023052",
	//         "clQReqId": "",
	//         "cnvtPx": "2932.40104429",
	//         "origRfqSz": "30",
	//         "quoteCcy": "USDT",
	//         "quoteId": "quoterETH-USDT16461885104612381",
	//         "quoteSz": "30",
	//         "quoteTime": "1646188510461",
	//         "rfqSz": "30",
	//         "rfqSzCcy": "USDT",
	//         "side": "buy",
	//         "ttlMs": "10000"
	//     }
	//
	// createConvertTrade
	//
	//     {
	//         "baseCcy": "ETH",
	//         "clTReqId": "",
	//         "fillBaseSz": "0.01023052",
	//         "fillPx": "2932.40104429",
	//         "fillQuoteSz": "30",
	//         "instId": "ETH-USDT",
	//         "quoteCcy": "USDT",
	//         "quoteId": "quoterETH-USDT16461885104612381",
	//         "side": "buy",
	//         "state": "fullyFilled",
	//         "tradeId": "trader16461885203381437",
	//         "ts": "1646188520338"
	//     }
	//
	// fetchConvertTrade, fetchConvertTradeHistory
	//
	//     {
	//         "clTReqId": "",
	//         "instId": "ETH-USDT",
	//         "side": "buy",
	//         "fillPx": "2932.401044",
	//         "baseCcy": "ETH",
	//         "quoteCcy": "USDT",
	//         "fillBaseSz": "0.01023052",
	//         "state": "fullyFilled",
	//         "tradeId": "trader16461885203381437",
	//         "fillQuoteSz": "30",
	//         "ts": "1646188520000"
	//     }
	//
	fromCurrency := GetArg(optionalArgs, 0, nil)
	_ = fromCurrency
	toCurrency := GetArg(optionalArgs, 1, nil)
	_ = toCurrency
	var timestamp any = this.SafeInteger2(conversion, "quoteTime", "ts")
	var fromCoin any = this.SafeString(conversion, "baseCcy")
	var fromCode any = this.SafeCurrencyCode(fromCoin, fromCurrency)
	var to any = this.SafeString(conversion, "quoteCcy")
	var toCode any = this.SafeCurrencyCode(to, toCurrency)
	return map[string]any{
		"info":         conversion,
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"id":           this.SafeStringN(conversion, []any{"clQReqId", "tradeId", "quoteId"}),
		"fromCurrency": fromCode,
		"fromAmount":   this.SafeNumber2(conversion, "baseSz", "fillBaseSz"),
		"toCurrency":   toCode,
		"toAmount":     this.SafeNumber2(conversion, "quoteSz", "fillQuoteSz"),
		"price":        this.SafeNumber2(conversion, "cnvtPx", "fillPx"),
		"fee":          nil,
	}
}

